SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for ich_news
-- ----------------------------
DROP TABLE IF EXISTS `ich_news`;
CREATE TABLE `ich_news`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标题',
  `region` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属区县：莲都区、龙泉市、青田县等',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '正文',
  `cover_image` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图 URL',
  `publish_time` datetime(6) NULL DEFAULT NULL,
  `source` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '来源',
  `create_time` datetime(6) NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1009 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '非遗资讯表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of ich_news
-- ----------------------------
INSERT INTO `ich_news` VALUES (1, '2025非遗传播创新案例公布 丽水4项上榜数量居全省第一', '丽水市', '近日，文化和旅游部民族民间文艺发展中心正式公布了2025年度非遗传播创新案例评选结果，丽水市共有4个非遗代表性项目成功入选，入选数量位居全省首位，成为此次评选中表现最为亮眼的地级市。\n\n据了解，本次评选共设置“非遗+展示展演”、“非遗+国际交流”、“非遗+工作坊”等多个类别，旨在挖掘和推广全国范围内具有创新性和示范意义的非遗传播实践。丽水市入选的4个案例各具特色、亮点纷呈：其中，《云和包山花鼓戏活态传承与创新传播案例——以现代剧目创作与多维传播赋能非遗活化》与《传统与现代的非遗对话——丽水沉浸式非遗情景展演》双双入选“非遗+展示展演”创新案例，展现了丽水在非遗舞台化表达和沉浸式体验方面的探索成果；《向新而生 跨海传韵——青田非遗的世界文化对话之旅》入选“非遗+国际交流”创新案例，彰显了青田石雕、青田鱼灯等非遗项目在国际文化交流中的独特魅力；《遂昌长粽工坊带动乡村振兴》则入选“非遗+工作坊”创新案例，生动诠释了非遗技艺传承与乡村产业发展的深度融合。\n\n这些入选案例不仅体现了丽水市在非物质文化遗产保护与传承领域的积极探索与不懈努力，更为非遗的活态传承与创新发展提供了可复制、可推广的“丽水样本”。近年来，丽水市持续加大非遗保护力度，创新传播方式，推动非遗融入现代生活，取得了显著成效。此次多项案例入选省级乃至全国性创新案例，是对丽水非遗工作的充分肯定，也将激励丽水进一步做好非遗的保护、传承与发展工作。', '/pictures/2025非遗传播创新案例公布 丽水4项上榜数量居全省第一_1.jpg', '2025-06-14 00:00:00.000000', '丽水市人民政府', '2025-06-15 00:00:00.000000');
INSERT INTO `ich_news` VALUES (2, '丽水13件作品入选2025“浙派好礼” 非遗文创备受青睐', '丽水市', '近日，由浙江省文化和旅游厅主办的2025“浙派好礼”文创产品和旅游商品评选结果正式揭晓，丽水市共有13件优秀作品脱颖而出，成功入选。这一成绩充分展示了丽水在文创产品研发和非遗活态转化方面的雄厚实力。\n\n据了解，本次入选的13件作品涵盖了非遗文创、文博文创、特色生活文创等多个类别，既有传统文化的深厚底蕴，又融入了现代设计的时尚元素。其中，非遗类作品表现尤为抢眼，共有6项入选，包括采用传统竹编工艺制作的“吃饱福-竹纤维盘”、以缙云烧饼为灵感设计的“缙云烧饼主题饰品《再‘焦’一点》”、融合龙泉宝剑锻造技艺的“宝剑-同心剑”、专为绘画爱好者设计的“尼奥尼粗杆橡皮笔”、运用松阳传统茶染工艺打造的“松风茶韵·茶染平田”，以及采用手工工艺制成的“香茶·手工茶香珠”。这些作品将古老的非遗技艺与现代审美需求巧妙结合，既保留了传统工艺的精髓，又赋予了产品新的生命力。\n\n“浙派好礼”评选活动旨在挖掘和推出一批具有浙江特色、文化内涵和市场潜力的文创产品，推动文旅深度融合发展。丽水此次入选的13件作品，不仅展现了丽水非遗技艺与现代创意设计的完美融合，更体现了丽水文创产业蓬勃发展的良好态势。这些兼具文化底蕴与实用美感的文创产品，让原本“养在深闺人未识”的非遗技艺真正“活”了起来，通过创意转化走进百姓日常生活，成为传播丽水文化、讲好丽水故事的最佳载体。', '/pictures/丽水13件作品入选2025“浙派好礼” 非遗文创备受青睐_1.png', '2025-10-26 00:00:00.000000', '丽水市人民政府', '2025-10-27 00:00:00.000000');
INSERT INTO `ich_news` VALUES (3, '莲都区公布第九批非遗代表性项目名录 12项传统技艺与民俗入选', '莲都区', '为不断完善非物质文化遗产代表性项目名录体系，进一步推进非遗资源的抢救、保护和传承工作，莲都区人民政府日前正式发文公布了第九批非物质文化遗产代表性项目名录。经过省、市非遗专家的严格审定及社会公示程序，最终确定“潘百庙会”、“莲城雾峰茶制作技艺”等12个项目正式入选。\n\n本批公布的名录涵盖民俗、传统技艺、传统医药、传统体育游艺四大类别，项目内容丰富、地方特色鲜明。其中民俗类共有3项入选，包括历史悠久、群众基础深厚的潘百庙会、三官堂庙会和大庭庙会，这些民俗活动承载着当地百姓的集体记忆和文化认同；传统技艺类共有6项入选，数量最多，包括莲城雾峰茶制作技艺、雅溪山粉丝制作技艺、梅苑卤鸭传统制作技艺、畲族红粬酒酿造技艺，以及两项莲都特色小吃制作技艺（作为拓展项目），这些技艺代代相传，凝聚着民间智慧和生活经验；传统医药类有1项入选，为同恩堂养生膏制作技艺，体现了中医药文化在民间的传承与发展；传统体育游艺类有2项入选，分别为摇锅和蹴石磉，这两项活动兼具竞技性与趣味性，是当地群众喜闻乐见的传统娱乐方式。\n\n莲都区文旅局相关负责人表示，第九批非遗项目的公布，将进一步丰富莲都区的非遗文化宝库，为后续的保护传承工作奠定坚实基础。下一步，莲都区将按照“保护为主、抢救第一、合理利用、传承发展”的工作方针，制定详细的保护计划，落实各项保护措施，让这些珍贵的非物质文化遗产在新时代焕发出新的生机与活力。', '/pictures/莲都区公布第九批非遗代表性项目名录 12项传统技艺与民俗入选.webp', '2025-11-06 00:00:00.000000', '莲都区人民政府', '2025-11-07 00:00:00.000000');
INSERT INTO `ich_news` VALUES (4, '光影里的非遗嘉年华——2025丽水摄影节“非遗巡街”盛大举行', '丽水市', '11月8日晚，第六届国际摄影研讨会暨2025丽水摄影节在浙江省丽水市盛大开幕。与往届不同的是，本届开幕式以一场别开生面的露天“非遗巡街”活动惊艳亮相，11支各具特色的非遗方阵沿丽水市主城区2.8公里路线徐徐展开巡游，为现场数万名市民和来自世界各地的摄影爱好者们带来了一场视觉与文化的双重盛宴。\n\n巡游队伍堪称丽水非遗的一次集中大展演。队伍最前方，龙泉剑瓷方阵格外引人注目，青瓷拉坯艺人现场展示指尖技艺，宝剑锻造师傅则挥舞铁锤，再现“龙泉宝剑”的锻造过程；紧随其后的是海潮线拉狮子方阵，这一源自唐代的舞狮技艺以“翻云梯”等高难度动作赢得阵阵喝彩；缙云婺剧方阵则带来了经典片段《穆桂英挂帅》，演员们身着华丽戏服，唱念做打有板有眼；景宁畲族婚俗与服饰秀方阵成为当晚的“颜值担当”，绚丽多彩的畲族传统服饰和独特的婚俗礼仪展示，让观众仿佛置身于畲乡的喜庆氛围中。此外，还有遂昌昆曲十番、庆元菇民戏、松阳高腔等非遗项目轮番登场，整条街道成为流动的非遗博物馆。\n\n传统非遗与摄影艺术在此刻完美交汇，来自世界各地的摄影师们举起相机，用镜头捕捉每一个精彩瞬间。古老的传统文化在现代光影技术的记录下，焕发出新的活力与魅力。这场别开生面的“非遗巡街”活动，不仅成为本届摄影节最令人印象深刻的开幕亮点，更向世界展示了丽水深厚的文化底蕴和非遗保护的丰硕成果。', '/pictures/光影里的非遗嘉年华——2025丽水摄影节“非遗巡街”盛大举行.jpg', '2025-11-08 00:00:00.000000', '新华网', '2025-11-09 00:00:00.000000');
INSERT INTO `ich_news` VALUES (5, '缙云县第八批非物质文化遗产代表性项目名录公布 7个项目入选', '缙云县', '为进一步健全县级非物质文化遗产代表性项目名录体系，推动优秀传统文化的保护与传承，缙云县人民政府于12月11日正式发文，公布了第八批缙云县非物质文化遗产代表性项目名录。经过前期申报、专家评审、社会公示等严格程序，最终共有7个项目成功入选。\n\n本批公布的名录包括传统技艺和传统医药两大类别，充分体现了缙云县非遗资源的丰富性和多样性。传统技艺类共有5项入选，分别是缙云油焖笋制作技艺、楼氏酥饼制作技艺、畲族蓝染制作技艺、缙云清明粿制作技艺、溶江花灯制作技艺。这些技艺项目扎根乡土，与百姓日常生活息息相关，既有舌尖上的美味，也有指尖上的艺术，具有浓郁的缙云地方特色。传统医药类共有2项入选，分别为归一针灸疗法和缙云陶氏传统膏药制作技艺。这两项传统医药项目世代传承，蕴含着民间医药文化的智慧结晶，至今仍在当地百姓的健康生活中发挥着积极作用。\n\n缙云县政府在通知中强调，各乡镇（街道）和有关部门要充分认识非物质文化遗产保护工作的重要性，按照《中华人民共和国非物质文化遗产法》和《浙江省非物质文化遗产保护条例》的要求，扎实做好新入选非遗名录项目的保护、传承和管理工作。要制定科学的保护规划，落实各项保护措施，鼓励和支持代表性传承人开展传习活动，推动非遗融入现代生活，为建设共同富裕美好缙云、促进文化大发展大繁荣作出积极贡献。据悉，截至目前，缙云县已拥有各级非遗代表性项目百余项，非遗保护工作呈现良好发展态势。', '/pictures/缙云县第八批非物质文化遗产代表性项目名录公布 7个项目入选.jpeg', '2025-12-15 00:00:00.000000', '缙云县人民政府', '2025-12-16 00:00:00.000000');
INSERT INTO `ich_news` VALUES (6, '非遗盛宴向全国展示丽水魅力 央视直播关注“丽水祥龙闹元宵”', '丽水市', '3月2日晚，正值农历正月十三，丙午（2026）“丽水祥龙闹元宵”活动在丽水市区隆重举行。这场具有浓郁地方特色的文化盛会，不仅点燃了全城市民的节日热情，更吸引了央视新闻频道的关注，通过直播镜头向全国观众展示了丽水非遗的独特魅力。\n\n当晚7时许，伴随着喧天的锣鼓声和欢快的唢呐声，由30余支队伍、近千名演职人员组成的巡游方阵从丽水市体育中心出发，沿市区主要街道缓缓行进。巡游队伍中，最引人注目的当属来自全市各县（市、区）的“祥龙”方阵：莲都的板龙长达百米，蜿蜒起伏，气势恢宏；龙泉的安仁板凳龙以板凳相连，龙身灯火通明，别具一格；青田的鱼灯龙则模仿江中鱼群，灵动活泼，栩栩如生；还有缙云的钢叉龙、遂昌的车龙、松阳的稻草龙……各式各样的龙灯在夜色中熠熠生辉，舞龙者们精神抖擞，将龙的威猛与灵动演绎得淋漓尽致。除了舞龙表演，巡游队伍中还穿插了畲族歌舞、婺剧折子戏、处州乱弹等非遗展演，整条街道成为欢乐的海洋。\n\n央视新闻频道的直播镜头全程跟随巡游队伍，主持人现场解说，将丽水元宵闹龙的盛况实时传递给全国观众。镜头中，市民们扶老携幼，沿街观看，脸上洋溢着幸福的笑容；舞龙者们挥汗如雨，激情投入，展现出昂扬向上的精神风貌。这场持续近三个小时的非遗盛宴，不仅让丽水市民度过了一个难忘的元宵佳节，更通过央视的镜头，向全国观众生动展示了丽水深厚的文化底蕴和非遗保护的丰硕成果，让“丽水祥龙”成为一张闪亮的城市文化名片。', '/pictures/非遗盛宴向全国展示丽水魅力 央视直播关注“丽水祥龙闹元宵”.jpg', '2026-03-02 00:00:00.000000', '央视新闻', '2026-03-03 00:00:00.000000');
INSERT INTO `ich_news` VALUES (7, '千年处州板龙“活”在元宵灯火处——莲都区“龙腾莲都·非遗贺春”活动侧记', '莲都区', '3月2日晚，农历正月十四，2026“丽水祥龙闹元宵”活动在丽水市区盛大举行。在这场全城瞩目的非遗盛宴中，莲都区以“龙腾莲都·非遗贺春”为主题，将西溪板龙、跑马灯、丽水吹打、高跷、迷你小板龙等非遗项目串联成珠，让沉睡的传统文化在灯火璀璨中“活”了起来。\n\n当晚6时，处州公园北门，随着三声锣鼓炸响，一条328米长的西溪板龙缓缓入场。这条巨龙本身堪称一座“流动的非遗博物馆”——龙头高5.8米，159节龙身精巧衔接，融合了处州乱弹、丽水吹打、竹篾编制、剪贴画、采茶灯、绘画、书法等7项传统技艺。更令人动容的是，这条龙由300位村民与志愿者耗时15000个小时纯手工打造，参与者年龄跨度从5岁到77岁，尽显传承力量。龙身上那抹翠绿勾线描绘的“云头勾”，是西溪村独有的吉祥符号，从祖辈传到现在，承载着乡土记忆与文化根脉。\n\n与雄浑的西溪板龙相映成趣的，是两条来自万象街道丽华村的迷你小板龙。80米长的龙身由废弃餐盘、旧木地板等环保材料拼接而成，100名舞龙队员中84人是5到10岁的孩子。他们身着鲜艳服装，眼神兴奋而坚定，以稚嫩却充满活力的动作，扛起了千年处州文脉的传承重任。\n\n在花园路与解放街路口，16匹跑马灯奔腾而来。这一源自1407年的“文化活化石”，在保留传统阵型精髓的基础上完成了现代化光影改造——LED柔性灯带与智能控光模块的加持，让跑马灯在夜色中如梦如幻。而在银泰城前方，省级非遗“丽水吹打”为千年通济堰量身谱写的《通济曲》正在奏响，二胡、笛子的东方韵味与大提琴、贝斯的浑厚底色交织碰撞，让千年古堰“开口唱歌”。\n\n莲都区文广旅体局相关负责人表示，近年来莲都区不断探索“非遗+节庆”“非遗+旅游”“非遗+文创”“非遗+研学”等融合路径，让非遗不再是博物馆里的静态陈列，而是流动在山水间的鲜活艺术。当千年非遗在元宵灯火中“活”起来，当传统文化在创新实践中“潮”起来，莲都正以这样的方式告诉世界：传承不是重复过去，而是让古老的生命在新时代绽放。', '/pictures/千年处州板龙“活”在元宵灯火处——莲都区“龙腾莲都·非遗贺春”活动侧记.webp', '2026-03-03 00:00:00.000000', '潮新闻', '2026-03-04 00:00:00.000000');
INSERT INTO `ich_news` VALUES (8, '小一姐姐打卡丽水 沉浸式体验非遗处州板龙魅力', '莲都区', '农历正月十四，知名传统文化传播者、中国青年国潮体验官、中国诗教推广大使小一姐姐走进浙江丽水莲都区，在西溪村沉浸式体验省级非遗处州板龙，感受千年非遗与元宵佳节的碰撞，向大众传递传统文化的传承温度。\n\n处州板龙起源于宋元时期，成熟于清代，迄今已有600余年历史，2009年被列入浙江省非物质文化遗产名录。西溪板龙作为其重要分支，更是当地的“千年村魂”。此次小一姐姐跟随2026“丽水祥龙闹元宵”活动，亲历了这场以“龙腾莲都·非遗贺春”为主题的巡游盛宴。\n\n当晚，随着三声锣鼓炸响，328米长的西溪板龙从处州公园北门缓缓入场，159节龙身精巧衔接，融合竹篾编制、绘画、书法等7项非遗技艺，堪称一座“流动的非遗馆”。据悉，这条巨龙由300位村民与志愿者耗时15000个小时纯手工打造，参与者年龄跨度从5岁到77岁，尽显传承力量。\n\n活动中，小一姐姐近距离观赏了板龙巡游，见证了迷你小板龙的灵动风采，还感受了跑马灯、丽水吹打等非遗项目的独特魅力。她全程记录体验过程，用镜头捕捉村民手工制作龙身的细节，记录孩子们挥舞迷你板龙的稚嫩身影，生动展现了非遗传承的鲜活场景。\n\n近年来，莲都区依托“非遗+”模式，推动处州板龙等非遗项目与节庆、旅游深度融合，让千年非遗走出博物馆、走进大众生活。小一姐姐的此次体验，以亲子视角为非遗传播注入新活力，进一步扩大了处州板龙的影响力，让更多人领略到丽水非遗的独特魅力与传统文化的深厚底蕴。小一姐姐表示，此次丽水之行收获满满，希望通过自己的镜头，让更多孩子了解处州板龙这份千年非遗，让传统文化在亲子相伴中代代相传、生生不息。', '/pictures/小一姐姐打卡丽水 沉浸式体验非遗处州板龙魅力.jpg', '2026-03-03 00:00:00.000000', '中国青年网', '2026-03-04 00:00:00.000000');

SET FOREIGN_KEY_CHECKS = 1;
